class Solution {
    public int minSwaps(int[] nums) {
        int n = nums.length;
        int ones = 0;
        for (int num : nums) {
            if (num == 1) {
                ones++;
            }
        }

        if (ones == 0) {
            return 0;
        }

        int[] temp = new int[n * 2];
        for (int i = 0; i < n; i++) {
            temp[i] = nums[i];
            temp[i + n] = nums[i];
        }

        int swaps = Integer.MAX_VALUE;
        int currSwaps = 0;
        int left = 0;
        int right = 0;
        int onesInWindow = 0;

        while (right < n * 2) {
            if (temp[right] == 1) {
                onesInWindow++;
            }

            if (right - left + 1 > ones) {
                if (temp[left] == 1) {
                    onesInWindow--;
                }
                left++;
            }

            if (right - left + 1 == ones) {
                currSwaps = ones - onesInWindow;
                swaps = Math.min(swaps, currSwaps);
            }

            right++;
        }

        return swaps;
    }
}
```
